/**
 * E2E Tests Generator
 *
 * Generates Playwright E2E tests from Prisma schema.
 * Produces `tests/e2e.generated.test.ts` which is always regenerated
 * and coexists with user-written `tests/e2e.test.ts`.
 *
 * What it generates:
 * - Auth helper (ensureLoggedIn) derived from the User model
 * - CRUD tests per non-User model (create, display, delete)
 * - App display test
 *
 * Generated by `shogo generate` - DO NOT EDIT
 */

import type { PrismaModel, PrismaField } from './prisma-generator'
import { getScalarFields, getRelationFields } from './prisma-generator'

// ============================================================================
// Types
// ============================================================================

export interface GeneratedTestFile {
  /** File name (e.g., 'e2e.generated.test.ts') */
  fileName: string
  /** Generated code */
  content: string
}

interface PrismaEnum {
  name: string
  values: { name: string }[]
}

export interface TestGeneratorConfig {
  /** Base URL for the app (default: 'http://localhost:3000') */
  baseUrl?: string
}

// ============================================================================
// Utilities
// ============================================================================

/**
 * Convert field name to a human-readable placeholder label.
 * e.g., 'firstName' -> 'First Name', 'title' -> 'Title'
 */
function toPlaceholder(fieldName: string): string {
  return fieldName
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/^./, s => s.toUpperCase())
}

/**
 * Convert model name to a display name.
 * e.g., 'TodoItem' -> 'Todo Item'
 */
function toDisplayName(name: string): string {
  return name.replace(/([a-z])([A-Z])/g, '$1 $2')
}

/**
 * Find the email field in a model.
 */
function findEmailField(model: PrismaModel): PrismaField | undefined {
  return model.fields.find(f =>
    f.name === 'email' ||
    f.name === 'emailAddress' ||
    (f.type === 'String' && f.name.toLowerCase().includes('email'))
  )
}

/**
 * Find the password field in a model.
 */
function findPasswordField(model: PrismaModel): PrismaField | undefined {
  return model.fields.find(f =>
    f.name === 'password' ||
    f.name === 'passwordHash' ||
    (f.type === 'String' && f.name.toLowerCase().includes('password'))
  )
}

/**
 * Find the name field in a model.
 */
function findNameField(model: PrismaModel): PrismaField | undefined {
  return model.fields.find(f =>
    f.name === 'name' ||
    f.name === 'displayName' ||
    f.name === 'fullName' ||
    f.name === 'username'
  )
}

/**
 * Find the User model.
 */
function findUserModel(models: PrismaModel[]): PrismaModel | undefined {
  return models.find(m => m.name === 'User')
}

/**
 * Get fillable fields for a model (scalar, non-auto, non-relation fields
 * that a user would fill in a form).
 */
function getFillableFields(model: PrismaModel): PrismaField[] {
  return getScalarFields(model).filter(f => {
    // Skip auto-generated fields
    if (f.isId) return false
    if (f.hasDefaultValue && (f.type === 'DateTime' || f.name === 'createdAt' || f.name === 'updatedAt')) return false
    if (f.name === 'createdAt' || f.name === 'updatedAt') return false
    // Skip foreign key fields (e.g., userId)
    if (f.name.endsWith('Id') || f.name.endsWith('_id')) return false
    // Skip Boolean with default (completed: false) - tested separately
    if (f.type === 'Boolean' && f.hasDefaultValue) return false
    return true
  })
}

/**
 * Generate a test value expression for a field based on its type.
 */
function testValueForField(field: PrismaField, enums: PrismaEnum[]): string {
  switch (field.type) {
    case 'String':
      return `\`Test ${toPlaceholder(field.name)} \${Date.now()}\``
    case 'Int':
      return `String(Math.floor(Math.random() * 1000))`
    case 'Float':
      return `String((Math.random() * 100).toFixed(2))`
    case 'Boolean':
      return `'true'` // will be handled as checkbox
    default: {
      // Check if it's an enum
      const enumDef = enums.find(e => e.name === field.type)
      if (enumDef && enumDef.values.length > 0) {
        return `'${enumDef.values[0].name}'`
      }
      return `'test-value'`
    }
  }
}

// ============================================================================
// Main Generator
// ============================================================================

/**
 * Generate Playwright E2E tests from Prisma models.
 *
 * Produces a single file `e2e.generated.test.ts` that:
 * 1. Tests app display
 * 2. Provides an ensureLoggedIn() helper
 * 3. Tests CRUD for each non-User model
 */
export function generateTests(
  models: PrismaModel[],
  enums: PrismaEnum[],
  config: TestGeneratorConfig = {}
): GeneratedTestFile {
  const baseUrl = config.baseUrl || 'http://localhost:3000'
  const userModel = findUserModel(models)
  const dataModels = models.filter(m => m.name !== 'User')
  const lines: string[] = []

  // --- File header ---
  lines.push(`/**`)
  lines.push(` * Auto-generated E2E Tests`)
  lines.push(` * Generated by \`shogo generate\` from prisma/schema.prisma - DO NOT EDIT`)
  lines.push(` *`)
  lines.push(` * These tests verify basic CRUD operations for each model.`)
  lines.push(` * For custom tests, create tests/e2e.test.ts (will not be overwritten).`)
  lines.push(` */`)
  lines.push(``)
  lines.push(`import { test, expect, type Page } from '@playwright/test'`)
  lines.push(``)
  lines.push(`const BASE_URL = process.env.BASE_URL || '${baseUrl}'`)
  lines.push(``)

  // --- Auth helper ---
  if (userModel) {
    const emailField = findEmailField(userModel)
    const passwordField = findPasswordField(userModel)
    const nameField = findNameField(userModel)

    lines.push(`// =============================================================================`)
    lines.push(`// Auth Helpers`)
    lines.push(`// =============================================================================`)
    lines.push(``)
    lines.push(`/**`)
    lines.push(` * Ensure the user is logged in. If not authenticated, signs up a new user.`)
    lines.push(` * Can be imported by user-written tests.`)
    lines.push(` */`)
    lines.push(`async function ensureLoggedIn(page: Page, testName: string) {`)
    lines.push(`  await page.goto(BASE_URL)`)
    lines.push(``)
    lines.push(`  // Check if already logged in by looking for a Sign Out button or main content`)
    lines.push(`  const signOutButton = page.getByRole('button', { name: /sign out|log out|logout/i })`)
    lines.push(`  const isLoggedIn = await signOutButton.isVisible({ timeout: 3000 }).catch(() => false)`)
    lines.push(`  if (isLoggedIn) return`)
    lines.push(``)
    lines.push(`  // Look for the email input (login/signup form)`)

    if (emailField) {
      const emailPlaceholder = toPlaceholder(emailField.name)
      lines.push(`  const emailInput = page.getByPlaceholder('${emailPlaceholder}')`)
      lines.push(`  const hasLoginForm = await emailInput.isVisible({ timeout: 5000 }).catch(() => false)`)
      lines.push(`  if (!hasLoginForm) return // Neither logged in nor login form visible`)
      lines.push(``)
      lines.push(`  // Switch to sign-up mode if there's a "Sign up" link`)
      lines.push(`  const signUpLink = page.getByRole('button', { name: /sign up/i })`)
      lines.push(`  if (await signUpLink.isVisible({ timeout: 2000 }).catch(() => false)) {`)
      lines.push(`    await signUpLink.click()`)
      lines.push(`  }`)
      lines.push(``)

      // Fill name if available (must be before email in signup forms)
      if (nameField) {
        const namePlaceholder = toPlaceholder(nameField.name)
        lines.push(`  // Fill name`)
        lines.push(`  const nameInput = page.getByPlaceholder('${namePlaceholder}')`)
        lines.push(`  if (await nameInput.isVisible({ timeout: 1000 }).catch(() => false)) {`)
        lines.push(`    await nameInput.fill('E2E Test User')`)
        lines.push(`  }`)
        lines.push(``)
      }

      // Fill email
      lines.push(`  // Fill email`)
      lines.push(`  const testEmail = \`test-\${testName}-\${Date.now()}@example.com\``)
      lines.push(`  await emailInput.fill(testEmail)`)
      lines.push(``)

      // Fill password if the model has one
      if (passwordField) {
        const pwPlaceholder = toPlaceholder(passwordField.name)
        lines.push(`  // Fill password`)
        lines.push(`  await page.getByPlaceholder('${pwPlaceholder}').fill('test1234')`)
        lines.push(``)
      }

      // Submit
      lines.push(`  // Submit signup form`)
      lines.push(`  const submitButton = page.getByRole('button', { name: /create account|sign up|get started/i })`)
      lines.push(`  await submitButton.click()`)
      lines.push(``)
      lines.push(`  // Wait for app to load after auth`)
      lines.push(`  await page.waitForTimeout(2000)`)
    }

    lines.push(`}`)
    lines.push(``)
  }

  // --- Helper to add an item for a model ---
  for (const model of dataModels) {
    const fillable = getFillableFields(model)
    if (fillable.length === 0) continue

    const displayName = toDisplayName(model.name)
    const fnName = `add${model.name}`

    lines.push(`/**`)
    lines.push(` * Helper to create a ${displayName} via the UI.`)
    lines.push(` */`)
    lines.push(`async function ${fnName}(page: Page, testValue: string) {`)

    // Fill each fillable field
    for (const field of fillable) {
      const placeholder = toPlaceholder(field.name)
      if (field.type === 'Boolean') {
        lines.push(`  // Toggle ${field.name}`)
        lines.push(`  const ${field.name}Checkbox = page.getByLabel('${placeholder}')`)
        lines.push(`  if (await ${field.name}Checkbox.isVisible({ timeout: 1000 }).catch(() => false)) {`)
        lines.push(`    await ${field.name}Checkbox.check()`)
        lines.push(`  }`)
      } else if (field.kind === 'enum') {
        const enumDef = enums.find(e => e.name === field.type)
        if (enumDef && enumDef.values.length > 0) {
          lines.push(`  // Select ${field.name}`)
          lines.push(`  const ${field.name}Select = page.getByLabel('${placeholder}')`)
          lines.push(`  if (await ${field.name}Select.isVisible({ timeout: 1000 }).catch(() => false)) {`)
          lines.push(`    await ${field.name}Select.selectOption('${enumDef.values[0].name}')`)
          lines.push(`  }`)
        }
      } else {
        // String/Int/Float - use placeholder-based input
        const isMainField = field === fillable[0]
        if (isMainField) {
          // First field uses the test value (unique identifier)
          lines.push(`  // Fill ${field.name} (primary identifier)`)
          lines.push(`  const ${field.name}Input = page.getByPlaceholder('${placeholder}')`)
          lines.push(`  if (await ${field.name}Input.isVisible({ timeout: 2000 }).catch(() => false)) {`)
          lines.push(`    await ${field.name}Input.click()`)
          lines.push(`    await ${field.name}Input.fill(testValue)`)
          lines.push(`  }`)
        } else {
          lines.push(`  // Fill ${field.name}`)
          lines.push(`  const ${field.name}Input = page.getByPlaceholder('${placeholder}')`)
          lines.push(`  if (await ${field.name}Input.isVisible({ timeout: 1000 }).catch(() => false)) {`)
          lines.push(`    await ${field.name}Input.fill(${testValueForField(field, enums)})`)
          lines.push(`  }`)
        }
      }
    }

    // Click submit
    lines.push(``)
    lines.push(`  // Submit the form`)
    lines.push(`  const submitButton = page.getByRole('button', { name: /add|create|save|submit/i })`)
    lines.push(`  if (await submitButton.isEnabled({ timeout: 2000 }).catch(() => false)) {`)
    lines.push(`    await submitButton.click()`)
    lines.push(`  }`)
    lines.push(``)
    lines.push(`  // Wait for the item to appear`)
    lines.push(`  await expect(page.getByText(testValue)).toBeVisible({ timeout: 5000 })`)
    lines.push(`}`)
    lines.push(``)
  }

  // --- Test describe block ---
  lines.push(`// =============================================================================`)
  lines.push(`// Generated Tests`)
  lines.push(`// =============================================================================`)
  lines.push(``)
  lines.push(`test.describe('Generated CRUD Tests', () => {`)

  // --- App display test ---
  lines.push(`  test('should display the app', async ({ page }) => {`)
  lines.push(`    await page.goto(BASE_URL)`)
  lines.push(`    // App should load without errors`)
  lines.push(`    await expect(page.locator('body')).toBeVisible()`)
  lines.push(`    // Should have at least one heading`)
  lines.push(`    const heading = page.getByRole('heading').first()`)
  lines.push(`    await expect(heading).toBeVisible({ timeout: 10000 })`)
  lines.push(`  })`)
  lines.push(``)

  // --- Auth test ---
  if (userModel) {
    lines.push(`  test('should handle authentication', async ({ page }) => {`)
    lines.push(`    await ensureLoggedIn(page, 'auth')`)
    lines.push(`    // After login, should see main app content`)
    lines.push(`    await expect(page.locator('body')).toBeVisible()`)
    lines.push(`  })`)
    lines.push(``)
  }

  // --- CRUD tests per model ---
  for (const model of dataModels) {
    const fillable = getFillableFields(model)
    if (fillable.length === 0) continue

    const displayName = toDisplayName(model.name)
    const fnName = `add${model.name}`
    const firstField = fillable[0]

    lines.push(`  test.describe('${displayName} CRUD', () => {`)

    // Create test
    lines.push(`    test('should create a ${displayName.toLowerCase()}', async ({ page }) => {`)
    if (userModel) {
      lines.push(`      await ensureLoggedIn(page, 'create-${model.name.toLowerCase()}')`)
    } else {
      lines.push(`      await page.goto(BASE_URL)`)
    }
    lines.push(``)
    lines.push(`      const testValue = \`E2E ${displayName} \${Date.now()}\``)
    lines.push(`      await ${fnName}(page, testValue)`)
    lines.push(``)
    lines.push(`      // Item should be visible`)
    lines.push(`      await expect(page.getByText(testValue)).toBeVisible({ timeout: 5000 })`)
    lines.push(`    })`)
    lines.push(``)

    // Display test
    lines.push(`    test('should display ${displayName.toLowerCase()} list', async ({ page }) => {`)
    if (userModel) {
      lines.push(`      await ensureLoggedIn(page, 'list-${model.name.toLowerCase()}')`)
    } else {
      lines.push(`      await page.goto(BASE_URL)`)
    }
    lines.push(``)
    lines.push(`      // Page should load without errors`)
    lines.push(`      await expect(page.locator('body')).toBeVisible({ timeout: 5000 })`)
    lines.push(`    })`)
    lines.push(``)

    // Delete test
    lines.push(`    test('should delete a ${displayName.toLowerCase()}', async ({ page }) => {`)
    if (userModel) {
      lines.push(`      await ensureLoggedIn(page, 'delete-${model.name.toLowerCase()}')`)
    } else {
      lines.push(`      await page.goto(BASE_URL)`)
    }
    lines.push(``)
    lines.push(`      // Create an item first`)
    lines.push(`      const testValue = \`Delete ${displayName} \${Date.now()}\``)
    lines.push(`      await ${fnName}(page, testValue)`)
    lines.push(``)
    lines.push(`      // Find and delete it`)
    lines.push(`      const item = page.locator('li, tr, [data-testid]').filter({ hasText: testValue })`)
    lines.push(`      const deleteButton = item.getByRole('button', { name: /delete|remove/i })`)
    lines.push(`      if (await deleteButton.isVisible({ timeout: 2000 }).catch(() => false)) {`)
    lines.push(`        await deleteButton.click()`)
    lines.push(`        // Item should be gone`)
    lines.push(`        await expect(page.getByText(testValue)).not.toBeVisible({ timeout: 5000 })`)
    lines.push(`      }`)
    lines.push(`    })`)

    lines.push(`  })`)
    lines.push(``)
  }

  lines.push(`})`)
  lines.push(``)

  return {
    fileName: 'e2e.generated.test.ts',
    content: lines.join('\n'),
  }
}
